'use client';

import React, { useState } from 'react';
import { PRESET_WIDGETS } from '@/lib/dashboard/presets';
import type { PresetWidget, WidgetType } from '@/lib/dashboard/types';

interface Props {
  onAdd: (preset: PresetWidget) => void;
  onClose: () => void;
}

const CATEGORIES = ['All', ...Array.from(new Set(PRESET_WIDGETS.map(p => p.category)))];

const TYPE_ICONS: Record<WidgetType, string> = {
  table: '⊞',
  bar: '▬',
  horizontal_bar: '≡',
  pie: '◔',
  line: '∿',
  area: '◬',
  heatmap: '▦',
  metric: '#',
};

const TYPE_LABELS: Record<WidgetType, string> = {
  table: 'Table',
  bar: 'Bar',
  horizontal_bar: 'H-Bar',
  pie: 'Pie',
  line: 'Line',
  area: 'Area',
  heatmap: 'Heatmap',
  metric: 'Metric',
};

export function AddWidgetDialog({ onAdd, onClose }: Props) {
  const [activeCategory, setActiveCategory] = useState('All');
  const [search, setSearch] = useState('');

  const filtered = PRESET_WIDGETS.filter(p => {
    const matchCat = activeCategory === 'All' || p.category === activeCategory;
    const matchSearch = !search || p.name.toLowerCase().includes(search.toLowerCase()) || p.description.toLowerCase().includes(search.toLowerCase());
    return matchCat && matchSearch;
  });

  return (
    <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div
        className="bg-[#0d1117] border border-slate-700 rounded-xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden shadow-2xl"
        onClick={e => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between px-5 py-4 border-b border-slate-800">
          <h2 className="text-sm font-semibold text-slate-100">Add Widget</h2>
          <button
            onClick={onClose}
            className="text-slate-500 hover:text-slate-300 transition-colors p-1"
          >
            <svg className="w-4 h-4" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
              <path d="M3 3l10 10M13 3L3 13" strokeLinecap="round" />
            </svg>
          </button>
        </div>

        {/* Search */}
        <div className="px-5 py-3 border-b border-slate-800/50">
          <input
            autoFocus
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder="Search widgets…"
            className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm text-slate-200 placeholder-slate-600 outline-none focus:border-amber-500/50 transition-colors"
          />
        </div>

        {/* Category tabs */}
        <div className="flex gap-1 px-5 py-2 border-b border-slate-800/50 overflow-x-auto scrollbar-none">
          {CATEGORIES.map(cat => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-3 py-1 rounded text-xs font-medium whitespace-nowrap transition-colors ${
                activeCategory === cat
                  ? 'bg-amber-500/20 text-amber-400 border border-amber-500/30'
                  : 'text-slate-400 hover:text-slate-200 hover:bg-slate-800'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Widget grid */}
        <div className="flex-1 overflow-y-auto p-4">
          {filtered.length === 0 ? (
            <div className="flex items-center justify-center h-32 text-slate-500 text-sm">
              No widgets found
            </div>
          ) : (
            <div className="grid grid-cols-2 gap-3">
              {filtered.map(preset => (
                <button
                  key={preset.id}
                  onClick={() => onAdd(preset)}
                  className="group flex flex-col gap-2 p-4 bg-slate-900/60 hover:bg-slate-800/80 border border-slate-800 hover:border-amber-500/30 rounded-lg text-left transition-all"
                >
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-amber-400/70 text-base font-mono">
                        {TYPE_ICONS[preset.widget_type]}
                      </span>
                      <span className="text-xs font-medium text-slate-200 group-hover:text-white">
                        {preset.name}
                      </span>
                    </div>
                    <span className="text-[10px] text-slate-600 font-mono">
                      {TYPE_LABELS[preset.widget_type]}
                    </span>
                  </div>
                  <p className="text-[11px] text-slate-500 leading-relaxed line-clamp-2">
                    {preset.description}
                  </p>
                  <div className="flex items-center gap-1.5 mt-1">
                    <span className="text-[10px] px-1.5 py-0.5 bg-slate-800 text-slate-500 rounded">
                      {preset.category}
                    </span>
                    <span className="text-[10px] text-slate-600">
                      {preset.config.columns.length} columns
                    </span>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
