"use client";

import React, { useState, useCallback } from 'react';
import { useDashboardList, useDashboard } from '@/lib/dashboard/hooks';
import { DashboardToolbar } from '@/components/dashboard/DashboardToolbar';
import { WidgetGrid } from '@/components/dashboard/WidgetGrid';
import { AddWidgetDialog } from '@/components/dashboard/AddWidgetDialog';
import type { UserWidget, PresetWidget, GridLayoutItem } from '@/lib/dashboard/types';

export default function DashboardPage() {
  const {
    dashboards,
    loading: listLoading,
    createDashboard,
    reload: reloadList,
  } = useDashboardList();

  const [activeDashboardId, setActiveDashboardId] = useState<string | null>(null);
  const [showAddWidget, setShowAddWidget] = useState(false);
  const [editingWidget, setEditingWidget] = useState<UserWidget | null>(null);

  const resolvedId = activeDashboardId ?? dashboards[0]?.id ?? null;

  const {
    dashboard,
    loading: dashLoading,
    saving,
    saveLayout,
    renameDashboard,
    deleteDashboard,
    duplicateDashboard,
    addWidget,
    updateWidget,
    deleteWidget,
    reload: reloadDashboard,
  } = useDashboard(resolvedId);

  // Auto-select first dashboard when list loads
  React.useEffect(() => {
    if (!activeDashboardId && dashboards.length > 0) {
      setActiveDashboardId(dashboards[0].id);
    }
  }, [dashboards, activeDashboardId]);

  const handleSelectDashboard = useCallback((id: string) => {
    setActiveDashboardId(id);
  }, []);

  const handleCreateDashboard = useCallback(async (name: string) => {
    const created = await createDashboard(name);
    if (created) setActiveDashboardId(created.id);
  }, [createDashboard]);

  const handleRenameDashboard = useCallback(async (_id: string, name: string) => {
    await renameDashboard(name);
  }, [renameDashboard]);

  const handleDeleteDashboard = useCallback(async (id: string) => {
    const ok = await deleteDashboard();
    if (ok) {
      await reloadList();
      const remaining = dashboards.filter(d => d.id !== id);
      setActiveDashboardId(remaining[0]?.id ?? null);
    }
  }, [deleteDashboard, reloadList, dashboards]);

  const handleDuplicateDashboard = useCallback(async (_id: string) => {
    const newId = await duplicateDashboard();
    if (newId) {
      await reloadList();
      setActiveDashboardId(newId);
    }
  }, [duplicateDashboard, reloadList]);

  const handleAddPreset = useCallback(async (preset: PresetWidget) => {
    setShowAddWidget(false);
    await addWidget(preset.widget_type, preset.name, preset.config);
  }, [addWidget]);

  const handleDeleteWidget = useCallback(async (widgetId: string) => {
    await deleteWidget(widgetId);
  }, [deleteWidget]);

  const handleCopyWidget = useCallback(async (widget: UserWidget) => {
    await addWidget(widget.widget_type, `${widget.title} (copy)`, widget.config_json);
  }, [addWidget]);

  const handleLayoutChange = useCallback((layout: GridLayoutItem[]) => {
    saveLayout(layout);
  }, [saveLayout]);

  const isLoading = listLoading || dashLoading;

  return (
    <div className="flex flex-col h-full min-h-0 -mx-4 -mt-4">
      {/* Toolbar */}
      <DashboardToolbar
        dashboards={dashboards}
        activeDashboardId={resolvedId}
        onSelectDashboard={handleSelectDashboard}
        onCreateDashboard={handleCreateDashboard}
        onRenameDashboard={handleRenameDashboard}
        onDeleteDashboard={handleDeleteDashboard}
        onDuplicateDashboard={handleDuplicateDashboard}
        onAddWidget={() => setShowAddWidget(true)}
        saving={saving}
      />

      {/* Grid area */}
      <div className="flex-1 overflow-y-auto px-4 py-3 min-h-0">
        {isLoading && !dashboard ? (
          <DashboardSkeleton />
        ) : !dashboard ? (
          <EmptyDashboardState onCreate={() => handleCreateDashboard('My Dashboard')} />
        ) : (
          <WidgetGrid
            widgets={dashboard.widgets ?? []}
            layout={dashboard.layout_json ?? []}
            onLayoutChange={handleLayoutChange}
            onEditWidget={(w) => setEditingWidget(w)}
            onDeleteWidget={handleDeleteWidget}
            onCopyWidget={handleCopyWidget}
          />
        )}
      </div>

      {/* Add widget dialog */}
      {showAddWidget && (
        <AddWidgetDialog
          onAdd={handleAddPreset}
          onClose={() => setShowAddWidget(false)}
        />
      )}

      {/* Edit widget placeholder — will be a WidgetEditor in next step */}
      {editingWidget && (
        <div
          className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4"
          onClick={() => setEditingWidget(null)}
        >
          <div
            className="bg-[#0d1117] border border-slate-700 rounded-xl p-6 max-w-md w-full shadow-2xl"
            onClick={e => e.stopPropagation()}
          >
            <h2 className="text-sm font-semibold text-slate-100 mb-4">Edit Widget</h2>
            <p className="text-slate-500 text-xs mb-4">
              Widget editor coming soon. You can delete and re-add widgets from the preset library.
            </p>
            <div className="flex items-center gap-2 justify-end">
              <button
                onClick={() => setEditingWidget(null)}
                className="px-3 py-1.5 text-xs text-slate-400 hover:text-slate-200 transition-colors"
              >
                Close
              </button>
              <button
                onClick={async () => {
                  await handleDeleteWidget(editingWidget.id);
                  setEditingWidget(null);
                }}
                className="px-3 py-1.5 text-xs bg-red-900/40 text-red-400 border border-red-800/50 rounded hover:bg-red-900/60 transition-colors"
              >
                Delete Widget
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── Sub-components ─────────────────────────────────────────────────────────────

function DashboardSkeleton() {
  return (
    <div className="grid grid-cols-2 gap-3 animate-pulse">
      {[1, 2, 3, 4].map(i => (
        <div key={i} className="h-48 bg-slate-900 rounded-lg border border-slate-800" />
      ))}
    </div>
  );
}

function EmptyDashboardState({ onCreate }: { onCreate: () => void }) {
  return (
    <div className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
      <div className="text-slate-600 text-5xl">⊞</div>
      <h3 className="text-slate-400 font-medium">No dashboards yet</h3>
      <p className="text-slate-600 text-sm text-center max-w-sm">
        Create your first dashboard to start tracking market data with customizable widgets.
      </p>
      <button
        onClick={onCreate}
        className="px-4 py-2 rounded-md bg-amber-500/15 hover:bg-amber-500/25 border border-amber-500/30 text-amber-400 text-sm font-medium transition-colors"
      >
        Create Dashboard
      </button>
    </div>
  );
}
