'use client';

import React, { useState, useRef, useEffect } from 'react';
import type { DashboardSummary } from '@/lib/dashboard/types';

interface Props {
  dashboards: DashboardSummary[];
  activeDashboardId: string | null;
  onSelectDashboard: (id: string) => void;
  onCreateDashboard: (name: string) => void;
  onRenameDashboard: (id: string, name: string) => void;
  onDeleteDashboard: (id: string) => void;
  onDuplicateDashboard: (id: string) => void;
  onAddWidget: () => void;
  saving?: boolean;
}

export function DashboardToolbar({
  dashboards,
  activeDashboardId,
  onSelectDashboard,
  onCreateDashboard,
  onRenameDashboard,
  onDeleteDashboard,
  onDuplicateDashboard,
  onAddWidget,
  saving,
}: Props) {
  const [showPicker, setShowPicker] = useState(false);
  const [showActions, setShowActions] = useState(false);
  const [renaming, setRenaming] = useState(false);
  const [renameVal, setRenameVal] = useState('');
  const [creatingNew, setCreatingNew] = useState(false);
  const [newName, setNewName] = useState('');
  const [confirmDelete, setConfirmDelete] = useState(false);

  const pickerRef = useRef<HTMLDivElement>(null);
  const actionsRef = useRef<HTMLDivElement>(null);

  const active = dashboards.find((d: DashboardSummary) => d.id === activeDashboardId);

  useEffect(() => {
    function onClickOutside(e: MouseEvent) {
      if (pickerRef.current && !pickerRef.current.contains(e.target as Node)) {
        setShowPicker(false);
      }
      if (actionsRef.current && !actionsRef.current.contains(e.target as Node)) {
        setShowActions(false);
      }
    }
    document.addEventListener('mousedown', onClickOutside);
    return () => document.removeEventListener('mousedown', onClickOutside);
  }, []);

  function startRename() {
    setRenameVal(active?.name ?? '');
    setRenaming(true);
    setShowActions(false);
  }

  function commitRename() {
    if (activeDashboardId && renameVal.trim()) {
      onRenameDashboard(activeDashboardId, renameVal.trim());
    }
    setRenaming(false);
  }

  function handleDelete() {
    if (!activeDashboardId) return;
    if (confirmDelete) {
      onDeleteDashboard(activeDashboardId);
      setConfirmDelete(false);
      setShowActions(false);
    } else {
      setConfirmDelete(true);
      setTimeout(() => setConfirmDelete(false), 3000);
    }
  }

  function commitNew() {
    if (newName.trim()) {
      onCreateDashboard(newName.trim());
      setNewName('');
      setCreatingNew(false);
      setShowPicker(false);
    }
  }

  return (
    <div className="flex items-center gap-2 px-4 py-2.5 border-b border-slate-800 bg-[#080d14] flex-wrap">
      {/* Dashboard picker */}
      <div className="relative" ref={pickerRef}>
        <button
          onClick={() => setShowPicker(p => !p)}
          className="flex items-center gap-2 px-3 py-1.5 rounded-md bg-slate-800/60 hover:bg-slate-800 border border-slate-700/50 transition-colors text-sm font-medium text-slate-200 min-w-[160px] max-w-[240px]"
        >
          <span className="text-amber-400 text-[11px]">⊞</span>
          <span className="truncate flex-1 text-left">{active?.name ?? 'Select Dashboard'}</span>
          <svg className="w-3.5 h-3.5 text-slate-400 shrink-0" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
            <path d="M4 6l4 4 4-4" strokeLinecap="round" strokeLinejoin="round" />
          </svg>
        </button>

        {showPicker && (
          <div className="absolute top-full left-0 mt-1 w-64 bg-[#1a1f2e] border border-slate-700 rounded-lg shadow-xl z-50 overflow-hidden">
            <div className="py-1 max-h-56 overflow-y-auto">
              {dashboards.map(d => (
                <button
                  key={d.id}
                  onClick={() => { onSelectDashboard(d.id); setShowPicker(false); }}
                  className={`w-full text-left px-3 py-2 text-sm hover:bg-slate-800/60 flex items-center gap-2 transition-colors ${
                    d.id === activeDashboardId ? 'text-amber-400' : 'text-slate-300'
                  }`}
                >
                  {d.is_default && <span className="text-amber-500 text-[10px]">★</span>}
                  <span className="truncate">{d.name}</span>
                </button>
              ))}
            </div>
            <div className="border-t border-slate-700 p-2">
              {creatingNew ? (
                <div className="flex gap-1.5">
                  <input
                    autoFocus
                    value={newName}
                    onChange={e => setNewName(e.target.value)}
                    onKeyDown={e => { if (e.key === 'Enter') commitNew(); if (e.key === 'Escape') setCreatingNew(false); }}
                    placeholder="Dashboard name..."
                    className="flex-1 bg-slate-900 border border-slate-600 rounded px-2 py-1 text-xs text-slate-200 placeholder-slate-600 outline-none focus:border-amber-500/50"
                  />
                  <button onClick={commitNew} className="px-2 py-1 text-xs bg-amber-500/20 text-amber-400 rounded hover:bg-amber-500/30 transition-colors">
                    Create
                  </button>
                </div>
              ) : (
                <button
                  onClick={() => setCreatingNew(true)}
                  className="w-full flex items-center gap-2 px-2 py-1.5 text-xs text-slate-400 hover:text-slate-200 rounded hover:bg-slate-800 transition-colors"
                >
                  <span className="text-amber-400">+</span> New Dashboard
                </button>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Rename inline */}
      {renaming ? (
        <div className="flex items-center gap-1.5">
          <input
            autoFocus
            value={renameVal}
            onChange={e => setRenameVal(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') commitRename(); if (e.key === 'Escape') setRenaming(false); }}
            className="bg-slate-900 border border-amber-500/40 rounded px-2 py-1 text-xs text-slate-200 outline-none w-40"
          />
          <button onClick={commitRename} className="text-xs text-amber-400 hover:text-amber-300 px-1">✓</button>
          <button onClick={() => setRenaming(false)} className="text-xs text-slate-500 hover:text-slate-300 px-1">✕</button>
        </div>
      ) : (
        /* Dashboard actions dropdown */
        active && (
          <div className="relative" ref={actionsRef}>
            <button
              onClick={() => setShowActions(p => !p)}
              className="p-1.5 text-slate-500 hover:text-slate-300 rounded hover:bg-slate-800 transition-colors"
              title="Dashboard options"
            >
              <svg className="w-4 h-4" viewBox="0 0 16 16" fill="currentColor">
                <circle cx="8" cy="3" r="1.2" />
                <circle cx="8" cy="8" r="1.2" />
                <circle cx="8" cy="13" r="1.2" />
              </svg>
            </button>
            {showActions && (
              <div className="absolute top-full left-0 mt-1 w-44 bg-[#1a1f2e] border border-slate-700 rounded-lg shadow-xl z-50 overflow-hidden">
                <button onClick={startRename} className="w-full text-left px-3 py-2 text-xs text-slate-300 hover:bg-slate-800 flex items-center gap-2">
                  <span>✎</span> Rename
                </button>
                <button
                  onClick={() => { onDuplicateDashboard(activeDashboardId!); setShowActions(false); }}
                  className="w-full text-left px-3 py-2 text-xs text-slate-300 hover:bg-slate-800 flex items-center gap-2"
                >
                  <span>⎘</span> Duplicate
                </button>
                <div className="border-t border-slate-700/50 mt-1 pt-1">
                  <button
                    onClick={handleDelete}
                    className={`w-full text-left px-3 py-2 text-xs flex items-center gap-2 ${
                      confirmDelete
                        ? 'text-red-400 bg-red-950/30'
                        : 'text-slate-400 hover:text-red-400 hover:bg-red-950/20'
                    }`}
                  >
                    <span>⊗</span> {confirmDelete ? 'Confirm delete?' : 'Delete'}
                  </button>
                </div>
              </div>
            )}
          </div>
        )
      )}

      <div className="flex-1" />

      {/* Saving indicator */}
      {saving && (
        <span className="text-[10px] text-slate-600 animate-pulse">Saving…</span>
      )}

      {/* Add widget CTA */}
      <button
        onClick={onAddWidget}
        className="flex items-center gap-1.5 px-3 py-1.5 rounded-md bg-amber-500/15 hover:bg-amber-500/25 border border-amber-500/30 text-amber-400 text-xs font-medium transition-colors"
      >
        <span className="text-base leading-none">+</span>
        Add Widget
      </button>
    </div>
  );
}
