'use client';

import React, { useCallback } from 'react';
import { ResponsiveGridLayout, useContainerWidth } from 'react-grid-layout';
import type { Layout, LayoutItem, ResponsiveLayouts } from 'react-grid-layout';
import type { UserWidget, GridLayoutItem } from '@/lib/dashboard/types';
import { WidgetCard } from './WidgetCard';

import 'react-grid-layout/css/styles.css';
import 'react-resizable/css/styles.css';

interface Props {
  widgets: UserWidget[];
  layout: GridLayoutItem[];
  onLayoutChange: (layout: GridLayoutItem[]) => void;
  onEditWidget: (widget: UserWidget) => void;
  onDeleteWidget: (widgetId: string) => void;
  onCopyWidget: (widget: UserWidget) => void;
}

const COLS = { lg: 12, md: 10, sm: 6, xs: 4, xxs: 2 };
const ROW_HEIGHT = 60;
const BREAKPOINTS = { lg: 1200, md: 996, sm: 768, xs: 480, xxs: 0 };

export function WidgetGrid({
  widgets,
  layout,
  onLayoutChange,
  onEditWidget,
  onDeleteWidget,
  onCopyWidget,
}: Props) {
  const { width, containerRef, mounted } = useContainerWidth({ initialWidth: 1280 });

  // Build layout items — merge stored layout with any new widgets not in layout yet
  const layoutItems: LayoutItem[] = widgets.map((w, idx) => {
    const stored = layout.find(l => l.i === w.id);
    if (stored) {
      return { i: stored.i, x: stored.x, y: stored.y, w: stored.w, h: stored.h, minW: 3, minH: 2 };
    }
    // Auto-place new widget
    const col = (idx % 2) * 6;
    const row = Math.floor(idx / 2) * 5;
    return { i: w.id, x: col, y: row, w: 6, h: 5, minW: 3, minH: 2 };
  });

  const handleLayoutChange = useCallback(
    (newLayout: Layout, _allLayouts: ResponsiveLayouts) => {
      const mapped: GridLayoutItem[] = [...newLayout].map((l: LayoutItem) => ({
        i: l.i,
        x: l.x,
        y: l.y,
        w: l.w,
        h: l.h,
      }));
      onLayoutChange(mapped);
    },
    [onLayoutChange]
  );

  if (widgets.length === 0) {
    return (
      <div ref={containerRef} className="flex flex-col items-center justify-center min-h-[60vh] gap-4">
        <div className="text-slate-600 text-5xl">⊞</div>
        <h3 className="text-slate-400 font-medium">No widgets yet</h3>
        <p className="text-slate-600 text-sm text-center max-w-sm">
          Click <span className="text-amber-400">+ Add Widget</span> in the toolbar to add your first widget from the preset library or create a custom one.
        </p>
      </div>
    );
  }

  return (
    <div ref={containerRef} className="w-full">
      {mounted && (
        <ResponsiveGridLayout
          className="layout"
          layouts={{ lg: layoutItems, md: layoutItems, sm: layoutItems }}
          cols={COLS}
          rowHeight={ROW_HEIGHT}
          breakpoints={BREAKPOINTS}
          width={width}
          onLayoutChange={handleLayoutChange}
          dragConfig={{ handle: '.widget-drag-handle' }}
          margin={[10, 10] as [number, number]}
          containerPadding={[0, 0] as [number, number]}
        >
          {widgets.map(widget => (
            <div key={widget.id} className="group relative">
              <div className="widget-drag-handle absolute inset-x-0 top-0 h-9 cursor-grab active:cursor-grabbing z-20 rounded-t-lg" />
              <WidgetCard
                widget={widget}
                onEdit={onEditWidget}
                onDelete={onDeleteWidget}
                onCopy={onCopyWidget}
              />
            </div>
          ))}
        </ResponsiveGridLayout>
      )}
    </div>
  );
}
