'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import type { WidgetColumn } from '@/lib/dashboard/types';

interface Props {
  rows: Record<string, unknown>[];
  columns: WidgetColumn[];
}

function formatValue(val: unknown, col: WidgetColumn): string {
  if (val === null || val === undefined) return '—';
  const n = Number(val);
  if (isNaN(n)) return String(val);
  switch (col.format) {
    case 'percent':
      return `${n >= 0 ? '+' : ''}${n.toFixed(2)}%`;
    case 'currency':
      return n >= 1e7
        ? `₹${(n / 1e7).toFixed(2)}Cr`
        : n >= 1e5
        ? `₹${(n / 1e5).toFixed(2)}L`
        : `₹${n.toLocaleString('en-IN', { maximumFractionDigits: 2 })}`;
    case 'number':
      return n >= 1e7
        ? `${(n / 1e7).toFixed(2)}Cr`
        : n >= 1e5
        ? `${(n / 1e5).toFixed(2)}L`
        : n.toLocaleString('en-IN', { maximumFractionDigits: 2 });
    default:
      return String(val);
  }
}

function valueColor(val: unknown, col: WidgetColumn): string {
  if (!col.colorCode) return '';
  const n = Number(val);
  if (isNaN(n)) return '';
  if (n > 0) return 'text-emerald-400';
  if (n < 0) return 'text-red-400';
  return 'text-slate-400';
}

export function WidgetTable({ rows, columns }: Props) {
  const [sortCol, setSortCol] = useState<string | null>(null);
  const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

  const symbolCol = columns.find(c => c.dslName === 'symbol');

  const sorted = [...rows].sort((a, b) => {
    if (!sortCol) return 0;
    const av = a[sortCol] ?? 0;
    const bv = b[sortCol] ?? 0;
    const cmp = Number(av) - Number(bv);
    return sortDir === 'asc' ? cmp : -cmp;
  });

  function handleSort(colId: string) {
    if (sortCol === colId) {
      setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    } else {
      setSortCol(colId);
      setSortDir('desc');
    }
  }

  return (
    <div className="overflow-auto h-full">
      <table className="w-full text-xs border-collapse">
        <thead className="sticky top-0 z-10">
          <tr className="bg-[#0d1117]">
            {columns.map(col => (
              <th
                key={col.id}
                onClick={() => handleSort(col.id)}
                className="px-2 py-1.5 text-left text-[11px] font-medium text-slate-400 cursor-pointer hover:text-amber-400 whitespace-nowrap border-b border-slate-800 select-none"
              >
                {col.label}
                {sortCol === col.id && (
                  <span className="ml-1 text-amber-400">
                    {sortDir === 'asc' ? '↑' : '↓'}
                  </span>
                )}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sorted.map((row, i) => {
            const symbol = symbolCol ? String(row[symbolCol.id] ?? row['symbol'] ?? '') : '';
            return (
              <tr
                key={i}
                className="border-b border-slate-800/50 hover:bg-slate-800/30 transition-colors"
              >
                {columns.map(col => {
                  const val = row[col.id];
                  const isSymbol = col.dslName === 'symbol';
                  return (
                    <td
                      key={col.id}
                      className={`px-2 py-1.5 whitespace-nowrap ${valueColor(val, col)}`}
                    >
                      {isSymbol && symbol ? (
                        <Link
                          href={`/stocks/${symbol}`}
                          className="text-amber-400 hover:text-amber-300 font-mono font-medium"
                        >
                          {symbol}
                        </Link>
                      ) : (
                        <span className={col.format === 'text' ? 'text-slate-300' : 'font-mono'}>
                          {formatValue(val, col)}
                        </span>
                      )}
                    </td>
                  );
                })}
              </tr>
            );
          })}
          {sorted.length === 0 && (
            <tr>
              <td colSpan={columns.length} className="py-8 text-center text-slate-500 text-xs">
                No data
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}
